<template><DomainRulesTab :domain-id="domainId" title="Rate Limits" summary="Limit request volume by IP or IP and path." :fields="fields" :columns="columns" :help-items="helpItems" :list="() => rateLimitApi.list(domainId)" :create="(v) => rateLimitApi.create(domainId, v as never)" :update="(id, v) => rateLimitApi.update(domainId, id, v)" :detach-managed="(id) => rateLimitApi.detachManaged(domainId, id)" :remove="(id) => rateLimitApi.delete(domainId, id)" /></template>
<script setup lang="ts">import DomainRulesTab from './DomainRulesTab.vue'; import { rateLimitApi } from '@/lib/api/rateLimit'; defineProps<{ domainId:string }>(); const helpItems=[{title:'Path examples',body:'Use / for site-wide limits, /login for authentication, or /api/ for API traffic.'},{title:'Thresholds',body:'Start higher than normal traffic, review analytics, then tighten for sensitive endpoints.'},{title:'Key type',body:'IP groups all requests from one visitor. IP + path tracks each path separately.'}]; const fields=[{key:'enabled',label:'Enabled',type:'checkbox' as const,default:true,help:'Disable instead of deleting when testing traffic impact.'},{key:'path_prefix',label:'Path prefix',default:'/',placeholder:'/login',help:'Apply the limit only to requests whose path starts with this value.'},{key:'requests_per_minute',label:'Requests/minute',type:'number' as const,default:60,placeholder:'60',help:'The maximum requests allowed per key during one minute.'},{key:'key_type',label:'Key type',options:['ip','ip_path'],default:'ip',help:'Choose how visitors are counted for this limit.'},{key:'priority',label:'Priority',type:'number' as const,default:100,placeholder:'100',help:'Lower priority values are evaluated first.'},{key:'action',label:'Action',options:['block'],default:'block',help:'Matched clients are blocked after exceeding the threshold.'}]; const columns=[{key:'enabled',label:'Enabled'},{key:'path_prefix',label:'Path'},{key:'requests_per_minute',label:'Requests/min'},{key:'key_type',label:'Key'},{key:'managed_by',label:'Managed'},{key:'actions',label:'Actions'}];</script>
